  "code": "def count_nums(arr):
    count = 0
    for n in arr:
        s = str(abs(n))
        first_digit = int(s[0])
        total = sum(int(ch) for ch in s)
        if n < 0:
            total -= 2 * first_digit
        if total > 0:
            count += 1
    return count",
